import{_ as e,o as l,c as a,a0 as i}from"./chunks/framework.Cyxxdjdf.js";const g=JSON.parse('{"title":"代码评审规范","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"contents/code_review.md","filePath":"contents/code_review.md"}'),o={name:"contents/code_review.md"};function s(r,t,n,d,c,p){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="代码评审规范" tabindex="-1">代码评审规范 <a class="header-anchor" href="#代码评审规范" aria-label="Permalink to &quot;代码评审规范&quot;">​</a></h1><p>Code Review（代码评审）不能是流于形式的走个过场 “一键 Approve”，也不会是针对个人的挑刺会。</p><p>它是拦截低级 Bug 流入生产环境的<strong>最后一道防线</strong>，更是团队内部技术对齐、消除技术债最有效的常态化机制。</p><p>一次好的 Code Review 能够：</p><ul><li>在问题进入主干前拦截 Bug 和设计缺陷</li><li>传递代码知识，让团队对业务和技术保持底层共识</li><li>推动规范常态化落地，形成统一的代码风格</li><li>降低新成员熟悉代码库的成本与劝退率</li></ul><h2 id="提交前自查" tabindex="-1">提交前自查 <a class="header-anchor" href="#提交前自查" aria-label="Permalink to &quot;提交前自查&quot;">​</a></h2><p>在发起 Pull Request 之前，作者应先完成自查，避免把低级问题留给 Reviewer。</p><div class="tip custom-block"><p class="custom-block-title">提交前清单</p><ul><li>本地编译 100% 通过，无报错、无警告</li><li>所有改动与 PR 描述严格一致，无多余文件</li><li>新增的公开 API、复杂逻辑、特殊兼容已添加注释</li><li>涉及核心接口变更，已同步更新调用方</li></ul></div><h2 id="pr-提交者规范" tabindex="-1">PR 提交者规范 <a class="header-anchor" href="#pr-提交者规范" aria-label="Permalink to &quot;PR 提交者规范&quot;">​</a></h2><h3 id="pr-粒度" tabindex="-1">PR 粒度 <a class="header-anchor" href="#pr-粒度" aria-label="Permalink to &quot;PR 粒度&quot;">​</a></h3><p>核心原则：<strong>一个 PR 只做一件事。</strong></p><div class="danger custom-block"><p class="custom-block-title">禁止大体量 PR</p><p>不要将多个不相关的功能或修复等，混在同一个 PR 中提交。</p><p>大 PR 的危害：</p><ul><li>Reviewer 无法在合理时间内完成审查</li><li>合并冲突概率大幅上升</li><li>回滚成本极高，可能无法精准还原</li></ul></div><p>PR 粒度参考：</p><table tabindex="0"><thead><tr><th>类型</th><th>建议粒度</th></tr></thead><tbody><tr><td>新功能</td><td>按最小可交付单元拆分，每个 PR 对应一个完整的小功能</td></tr><tr><td>Bug 修复</td><td>一个 PR 只修一个 Bug</td></tr><tr><td>重构</td><td>与业务改动分开提交，纯重构单独一个 PR</td></tr><tr><td>依赖升级</td><td>单独一个 PR，附上变更说明</td></tr></tbody></table><h3 id="pr-描述" tabindex="-1">PR 描述 <a class="header-anchor" href="#pr-描述" aria-label="Permalink to &quot;PR 描述&quot;">​</a></h3><p>PR 描述是 Reviewer 理解改动背景的第一入口，不能只写 &quot;fix bug&quot; 等无意义字符，更严禁留空。</p><p>推荐格式：<a href="/contents/git_conventions.html#commit-提交规范">详见 Commit 提交规范</a></p><div class="info custom-block"><p class="custom-block-title">提炼重点</p><p>描述不需要面面俱到，但至少要让 Reviewer 在没有额外沟通的情况下，理解这个 PR 在解决什么问题。</p></div><h2 id="review-审查者规范" tabindex="-1">Review 审查者规范 <a class="header-anchor" href="#review-审查者规范" aria-label="Permalink to &quot;Review 审查者规范&quot;">​</a></h2><h3 id="reviewer-职责" tabindex="-1">Reviewer 职责 <a class="header-anchor" href="#reviewer-职责" aria-label="Permalink to &quot;Reviewer 职责&quot;">​</a></h3><p>Reviewer 的核心职责应是保证代码质量，而不是一味查验代码与自己风格是否一致。</p><p>Reviewer 的核心职责应是捍卫主干代码的健壮性与架构秩序，而非一味查验代码风格是否与个人的主观偏好绝对一致。</p><div class="tip custom-block"><p class="custom-block-title">审查时重点关注</p><ul><li><strong>正确性</strong>：逻辑是否存在隐藏 Bug？，临界状态、边界条件是否做好了兜底处理？</li><li><strong>可维护性</strong>：职责是否清晰？是否违反单一职责原则？是否无端引入了不必要的隐性复杂度？</li><li><strong>规范符合度</strong>：命名是否语义化？是否严格遵循了本团队的规范？</li><li><strong>性能</strong>：是否存在明显的性能问题？（如：主线程耗时、内存泄漏）</li></ul></div><p>对于纯粹的个人习惯偏好（例如使用 Kotlin 语法糖的微小差异），只要符合现有规范，Reviewer 应保持技术包容。</p><h3 id="意见定级" tabindex="-1">意见定级 <a class="header-anchor" href="#意见定级" aria-label="Permalink to &quot;意见定级&quot;">​</a></h3><p>Reviewer 提交评论时<strong>必须明确带有统一的级别前缀</strong>，表明该意见的严重程度：</p><table tabindex="0"><thead><tr><th style="text-align:left;">级别前缀</th><th style="text-align:left;">含义说明</th><th style="text-align:center;">是否阻断合并</th><th style="text-align:left;">典型场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>[BLOCK]</code></strong></td><td style="text-align:left;"><strong>阻断级问题</strong></td><td style="text-align:center;"><strong>是</strong></td><td style="text-align:left;">存在明确 Bug 或严重设计问题、或严重违背核心架构职责。</td></tr><tr><td style="text-align:left;"><strong><code>[WARN]</code></strong></td><td style="text-align:left;"><strong>警告级建议</strong></td><td style="text-align:center;"><strong>否</strong></td><td style="text-align:left;">命名语义不够清晰、方法体积微大、缺乏必要的关键行背景注释、或存在更优雅的替代方案。</td></tr><tr><td style="text-align:left;"><strong><code>[QUS]</code></strong></td><td style="text-align:left;"><strong>疑问澄清</strong></td><td style="text-align:center;"><strong>否</strong></td><td style="text-align:left;">代码逻辑过于晦涩，Reviewer 无法直接看懂，需要 Author 解释设计意图。</td></tr><tr><td style="text-align:left;"><strong><code>[NIT]</code></strong></td><td style="text-align:left;"><strong>琐碎细节</strong></td><td style="text-align:center;"><strong>否</strong></td><td style="text-align:left;">错别字、多余的空行或空格、漏掉的换行等无伤大雅的排版问题。</td></tr></tbody></table><p>示例：</p><h3 id="评论语气" tabindex="-1">评论语气 <a class="header-anchor" href="#评论语气" aria-label="Permalink to &quot;评论语气&quot;">​</a></h3><p>评论要对事不对人，保持冷峻、专业客观的描述问题，而不是指责人。</p><p>好的评论示例：</p><div class="language-textmate vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textmate</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[BLOCK]：这里如果 `list` 为空会抛 `IndexOutOfBoundsException`，建议加一个边界判断。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>[WARN]：这个方法现在承担了两个职责，建议拆开，方便后续单独测试。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>[BLOCK]：这里用 `GlobalScope` 会导致协程在 Activity 销毁后仍然运行，建议改用 `viewModelScope`。</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">避免的评论方式</p><ul><li>&quot;这段代码写得很烂。&quot;（带有攻击性，毫无工程建设性）</li><li>&quot;你为什么要这样写？&quot;（质问语气，应改为提问 + 建议）</li><li>&quot;这完全不对，去改掉。&quot;（没有说明哪里不对，没有指引修改方向）</li></ul></div><h2 id="高频问题清单" tabindex="-1">高频问题清单 <a class="header-anchor" href="#高频问题清单" aria-label="Permalink to &quot;高频问题清单&quot;">​</a></h2><p>这是 Review 中频繁出现的问题黑榜，Author 在提交前应重点自查。</p><details class="details custom-block"><summary>展开查看高频雷区</summary><p><strong>内存与生命周期</strong></p><ul><li>非静态内部类或匿名类是否持有外部 Activity/Fragment 引用</li><li>Handler / Runnable 是否在 <code>onDestroy</code> 中移除</li><li>LiveData / StateFlow 观察者是否使用 <code>viewLifecycleOwner</code></li><li>ViewModel 是否持有 Context 或 View 引用</li></ul><p><strong>线程安全</strong></p><ul><li>数据库、文件 IO、等耗时操作是否在主线程执行</li><li>多线程访问的共享变量是否有适当的同步保护</li><li><code>GlobalScope</code> 是否被滥用</li></ul><p><strong>空安全</strong></p><ul><li>可空返回值是否有判空处理</li><li>强制 <code>!!</code> 断言非空是否有充分理由</li><li><code>@Nullable</code> / <code>@NonNull</code> 注解是否与实现一致</li></ul><p><strong>代码质量</strong></p><ul><li>是否存在重复逻辑，可以抽取公共方法</li><li>方法是否过于庞大，是否需要拆分</li><li>命名是否符合语义化规范</li><li>异常是否被静默吞掉</li></ul></details><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>Code Review 的价值在于持续。一次认真的 Review 能拦截 Bug，百次认真的 Review 能拉高并稳固整个团队的代码质量下限。</p><ul><li>作为 Author，把 PR 写清楚是对 Reviewer 时间的尊重。</li><li>作为 Reviewer，把问题说清楚是对团队代码库的负责。</li></ul>',39)])])}const h=e(o,[["render",s]]);export{g as __pageData,h as default};
